const CHALLENGE_LOOKUP = Object.fromEntries(CHALLENGES.map((challenge) => [challenge.id, challenge]));

const SKIN_LOOKUP = Object.fromEntries(SKINS.map((skin) => [skin.id, skin]));

function getDateKey(date = new Date()) {
  const year = date.getFullYear();
  const month = `${date.getMonth() + 1}`.padStart(2, '0');
  const day = `${date.getDate()}`.padStart(2, '0');
  return `${year}-${month}-${day}`;
}

function diffCalendarDays(previousDateKey, nextDateKey) {
  if (!previousDateKey || !nextDateKey) return null;
  const previousDate = new Date(`${previousDateKey}T00:00:00`);
  const nextDate = new Date(`${nextDateKey}T00:00:00`);
  const diffMs = nextDate.getTime() - previousDate.getTime();
  return Math.round(diffMs / 86400000);
}

function createDefaultProfile() {
  return {
    name: 'Player',
    xp: 0,
    level: 1,
    performancePreset: 'adaptive',
    selectedSkin: 'default',
    unlockedSkins: ['default'],
    completedChallenges: [],
    challengeProgress: {},
    stats: {
      totalMatches: 0,
      totalKills: 0,
      bestMass: 50,
      bestXp: 0,
    },
    dailyRewards: {
      lastClaimDate: null,
      streak: 0,
      bestStreak: 0,
      totalClaims: 0,
    },
  };
}

function getMetricValue(profile, matchSummary, metric) {
  switch (metric) {
    case 'matchKills':
      return matchSummary.matchKills || 0;
    case 'maxMass':
      return matchSummary.maxMass || 0;
    case 'totalKills':
      return profile.stats.totalKills || 0;
    case 'totalMatches':
      return profile.stats.totalMatches || 0;
    case 'dailyClaims':
      return profile.dailyRewards.totalClaims || 0;
    default:
      return 0;
  }
}

function ensureProfileShape(profile) {
  const defaultProfile = createDefaultProfile();
  const mergedProfile = {
    ...defaultProfile,
    ...profile,
    stats: {
      ...defaultProfile.stats,
      ...(profile.stats || {}),
    },
    dailyRewards: {
      ...defaultProfile.dailyRewards,
      ...(profile.dailyRewards || {}),
    },
  };

  mergedProfile.completedChallenges = Array.from(new Set(mergedProfile.completedChallenges || []));
  mergedProfile.challengeProgress = { ...(mergedProfile.challengeProgress || {}) };
  mergedProfile.level = ProfileManager.calculateLevel(mergedProfile.xp);
  mergedProfile.performancePreset = mergedProfile.performancePreset === 'ultra' ? 'ultra' : 'adaptive';

  mergedProfile.unlockedSkins = SKINS.filter((skin) => isSkinUnlocked(skin, mergedProfile)).map(
    (skin) => skin.id
  );

  if (!mergedProfile.unlockedSkins.includes(mergedProfile.selectedSkin)) {
    mergedProfile.selectedSkin = 'default';
  }

  return mergedProfile;
}

function isSkinUnlocked(skin, profile) {
  const unlock = skin.unlock || { type: 'level', level: skin.requiredLevel || 1 };
  switch (unlock.type) {
    case 'challenge':
      return (profile.completedChallenges || []).includes(unlock.challengeId);
    case 'dailyStreak':
      return (profile.dailyRewards?.bestStreak || 0) >= unlock.days;
    case 'dailyClaims':
      return (profile.dailyRewards?.totalClaims || 0) >= unlock.claims;
    case 'level':
    default:
      return (profile.level || 1) >= (unlock.level || skin.requiredLevel || 1);
  }
}

function updateChallengeState(profile, matchSummary = {}) {
  const newlyCompleted = [];
  for (const challenge of CHALLENGES) {
    const currentMetricValue = getMetricValue(profile, matchSummary, challenge.metric);
    const previousProgress = profile.challengeProgress[challenge.id] || 0;
    const nextProgress =
      challenge.progressType === 'best'
        ? Math.max(previousProgress, currentMetricValue)
        : currentMetricValue;

    profile.challengeProgress[challenge.id] = nextProgress;

    if (nextProgress >= challenge.target && !profile.completedChallenges.includes(challenge.id)) {
      profile.completedChallenges.push(challenge.id);
      newlyCompleted.push(challenge.id);
    }
  }

  return newlyCompleted;
}

export function getSkinById(id) {
  return SKIN_LOOKUP[id] || SKIN_LOOKUP.default;
}

export function getChallengeById(id) {
  return CHALLENGE_LOOKUP[id] || null;
}

export function getSkinUnlockRequirementText(skin) {
  const unlock = skin.unlock || { type: 'level', level: skin.requiredLevel || 1 };
  switch (unlock.type) {
    case 'challenge': {
      const challenge = getChallengeById(unlock.challengeId);
      return challenge ? challenge.description : 'Complete a hidden challenge';
    }
    case 'dailyStreak':
      return `Claim ${unlock.days} daily rewards in a row`;
    case 'dailyClaims':
      return `Claim ${unlock.claims} total daily rewards`;
    case 'level':
    default:
      return `Reach Lv ${unlock.level || skin.requiredLevel || 1}`;
  }
}

export function getDailyRewardStatus(profile, date = new Date()) {
  const safeProfile = ensureProfileShape(profile || createDefaultProfile());
  const todayKey = getDateKey(date);
  const lastClaimDate = safeProfile.dailyRewards.lastClaimDate;
  const claimedToday = lastClaimDate === todayKey;
  const previousDiff = diffCalendarDays(lastClaimDate, todayKey);
  const nextStreak = claimedToday
    ? safeProfile.dailyRewards.streak || 0
    : previousDiff === 1
    ? (safeProfile.dailyRewards.streak || 0) + 1
    : 1;
  const reward = DAILY_REWARDS[Math.min(nextStreak, DAILY_REWARDS.length) - 1];

  return {
    canClaim: !claimedToday,
    claimedToday,
    currentStreak: safeProfile.dailyRewards.streak || 0,
    nextStreak,
    reward,
  };
}

export class ProfileManager {
  static getProfile() {
    console.log('ProfileManager: getProfile called');
    const defaultProfile = createDefaultProfile();

    // localStorage may not exist in some environments (SSR, tests, incognito)
    if (typeof localStorage === 'undefined' || localStorage === null) {
      console.warn('ProfileManager: localStorage unavailable, using default profile');
      return defaultProfile;
    }

    try {
      const stored = localStorage.getItem('snakey_profile');
      if (stored) {
        const parsed = JSON.parse(stored);
        // guard in case JSON.parse returns null/undefined
        if (parsed && typeof parsed === 'object') {
          return ensureProfileShape({ ...defaultProfile, ...parsed });
        }
      }
    } catch (e) {
      console.error('Error reading profile', e);
      try {
        localStorage.removeItem('snakey_profile');
      } catch {
        return defaultProfile;
      }
    }
    return defaultProfile;
  }

  static saveProfile(profile) {
    localStorage.setItem('snakey_profile', JSON.stringify(ensureProfileShape(profile)));
  }

  static calculateLevel(xp) {
    // Basic curve: 1000 XP per level
    return Math.floor(Math.sqrt(xp / 500)) + 1;
  }

  static getLevelProgress(xp) {
    const currentLevel = this.calculateLevel(xp);
    const xpForCurrent = 500 * Math.pow(currentLevel - 1, 2);
    const xpForNext = 500 * Math.pow(currentLevel, 2);

    return {
      currentLevel,
      xpIntoLevel: xp - xpForCurrent,
      xpRequired: xpForNext - xpForCurrent,
      percent: ((xp - xpForCurrent) / (xpForNext - xpForCurrent)) * 100,
    };
  }

  static addXP(amount, matchSummary = {}) {
    const p = ensureProfileShape(this.getProfile());
    const oldLevel = p.level;
    const previousUnlocks = new Set(p.unlockedSkins || []);

    p.xp += amount;
    p.level = this.calculateLevel(p.xp);
    p.stats.totalMatches += 1;
    p.stats.totalKills += matchSummary.matchKills || 0;
    p.stats.bestMass = Math.max(p.stats.bestMass || 50, matchSummary.maxMass || 0);
    p.stats.bestXp = Math.max(p.stats.bestXp || 0, amount || 0);

    const newChallenges = updateChallengeState(p, matchSummary);
    const normalizedProfile = ensureProfileShape(p);
    const unlockedThisMatch = normalizedProfile.unlockedSkins.filter(
      (skinId) => !previousUnlocks.has(skinId)
    );

    this.saveProfile(normalizedProfile);

    return {
      leveledUp: normalizedProfile.level > oldLevel,
      newLevel: normalizedProfile.level,
      newUnlocks: unlockedThisMatch,
      newChallenges,
      profile: normalizedProfile,
    };
  }

  static claimDailyReward(date = new Date()) {
    const profile = ensureProfileShape(this.getProfile());
    const status = getDailyRewardStatus(profile, date);

    if (!status.canClaim) {
      return {
        claimed: false,
        reason: 'already-claimed',
        reward: status.reward,
        profile,
        newUnlocks: [],
      };
    }

    const previousUnlocks = new Set(profile.unlockedSkins || []);
    const todayKey = getDateKey(date);
    profile.dailyRewards.lastClaimDate = todayKey;
    profile.dailyRewards.streak = status.nextStreak;
    profile.dailyRewards.bestStreak = Math.max(
      profile.dailyRewards.bestStreak || 0,
      status.nextStreak
    );
    profile.dailyRewards.totalClaims = (profile.dailyRewards.totalClaims || 0) + 1;
    profile.xp += status.reward.xp;
    profile.level = this.calculateLevel(profile.xp);

    updateChallengeState(profile, {});
    const normalizedProfile = ensureProfileShape(profile);
    const newUnlocks = normalizedProfile.unlockedSkins.filter((skinId) => !previousUnlocks.has(skinId));

    this.saveProfile(normalizedProfile);

    return {
      claimed: true,
      reward: status.reward,
      profile: normalizedProfile,
      newUnlocks,
      newLevel: normalizedProfile.level,
    };
  }

  static grantBonusXP(amount, source = 'bonus') {
    const profile = ensureProfileShape(this.getProfile());
    const previousUnlocks = new Set(profile.unlockedSkins || []);
    const oldLevel = profile.level;

    profile.xp += amount;
    profile.level = this.calculateLevel(profile.xp);
    profile.stats.bestXp = Math.max(profile.stats.bestXp || 0, amount || 0);

    const normalizedProfile = ensureProfileShape(profile);
    const newUnlocks = normalizedProfile.unlockedSkins.filter((skinId) => !previousUnlocks.has(skinId));
    this.saveProfile(normalizedProfile);

    return {
      source,
      leveledUp: normalizedProfile.level > oldLevel,
      newLevel: normalizedProfile.level,
      newUnlocks,
      profile: normalizedProfile,
      xpGranted: amount,
    };
  }

  /**
   * Completely wipes the stored profile and returns the default object.
   * Useful for debugging or recovering from corrupted storage.
   */
  static resetProfile() {
    try {
      if (typeof localStorage !== 'undefined' && localStorage !== null) {
        localStorage.removeItem('snakey_profile');
      }
    } catch (e) {
      console.warn('ProfileManager.resetProfile: could not clear localStorage', e);
    }
    return this.getProfile();
  }
}
